// 📁 reverseText.js — итеративная реализация

function reverseText(str) {
    let result = '';
    // Идём с конца строки к началу
    for (let i = str.length - 1; i >= 0; i--) {
        result += str[i];
    }
    return result;
}

// Запусти тесты из шага 1 — все должны стать зелёными (GREEN)

console.log(reverseText(''));       // ''
console.log(reverseText('а'));      // 'а'
console.log(reverseText('hello'));  // 'olleh'
console.log(reverseText('Алия'));   // 'яилА'
console.log(reverseText('казак'));  // 'казак'

module.exports = { reverseText };
